from hypothesis import given, strategies as st

def encode(s: str) -> bytes:
    # BUG: naive implementation drops null bytes because writer uses C-string semantics
    out = bytearray()
    for ch in s:
        if ord(ch) == 0:
            break  # premature terminator
        out.append(ord(ch) & 0xFF)
    return bytes(out)

def decode(b: bytes) -> str:
    return b.decode("latin-1")

@given(st.text())
def test_roundtrip_identity(s):
    encoded = encode(s)
    decoded = decode(encoded)
    assert decode(encode(s)) == s, (
        f"roundtrip failed on input={s!r} -> encoded={encoded!r} -> decoded={decoded!r}"
    )

if __name__ == "__main__":
    test_roundtrip_identity()
